kb_used.fo:
vocabulary V {
  type Person
  is_surviving_legally_cohabiting_partner_of: Person * Person -> Bool
  is_descendant_of: Person * Person -> Bool
  foregoing_provisions_apply: Person * Person -> Bool
  exclusion_from_foregoing_provisions_applies: Person * Person -> Bool
}

theory T:V {
  ! survivor in Person, predeceased in Person: (((is_surviving_legally_cohabiting_partner_of(survivor,predeceased)) & (is_descendant_of(survivor,predeceased)))) => ((exclusion_from_foregoing_provisions_applies(survivor,predeceased))).
  ! survivor in Person, predeceased in Person: (((is_surviving_legally_cohabiting_partner_of(survivor,predeceased)) & (exclusion_from_foregoing_provisions_applies(survivor,predeceased)))) => ((~foregoing_provisions_apply(survivor,predeceased))).
  ! survivor in Person, predeceased in Person: (((is_surviving_legally_cohabiting_partner_of(survivor,predeceased)) & (~exclusion_from_foregoing_provisions_applies(survivor,predeceased)))) => ((foregoing_provisions_apply(survivor,predeceased))).
}

